private fun CardHistoryMonthSeed.toEntries(): List<CardHistorySeedEntry> {
    val values = rawValues.split('|').toMutableList().also { parsed ->
        while (parsed.size < daySequence.size) {
            parsed += ""
        }
    }
    val monthLength = YearMonth.of(year, month).lengthOfMonth()

    return daySequence.mapIndexedNotNull { index, day ->
        val amount = values.getOrNull(index)?.toLongOrNull() ?: return@mapIndexedNotNull null
        val useDate = if (day >= 10) {
            if (day > monthLength) return@mapIndexedNotNull null
            LocalDate.of(year, month, day)
        } else {
            val resolvedYear = if (month == 12) year + 1 else year
            val resolvedMonth = if (month == 12) 1 else month + 1
            if (resolvedYear !in 2024..2026) return@mapIndexedNotNull null
            LocalDate.of(resolvedYear, resolvedMonth, day)
        }
        if (useDate.year !in 2024..2026) return@mapIndexedNotNull null
        CardHistorySeedEntry(useDate = useDate, amount = amount)
    }
